function scoreEntry(entry,results){if(!results)return{total:0};let total=0;if(results.eastR1)(entry.picks.eastR1||[]).forEach((p,i)=>{if(p&&results.eastR1[i]&&p===results.eastR1[i])total+=1;});if(results.westR1)(entry.picks.westR1||[]).forEach((p,i)=>{if(p&&results.westR1[i]&&p===results.westR1[i])total+=1;});if(results.eastR2)(entry.picks.eastR2||[]).forEach((p,i)=>{if(p&&results.eastR2[i]&&p===results.eastR2[i])total+=2;});if(results.westR2)(entry.picks.westR2||[]).forEach((p,i)=>{if(p&&results.westR2[i]&&p===results.westR2[i])total+=2;});if(results.eastFinal&&entry.picks.eastFinal===results.eastFinal)total+=4;if(results.westFinal&&entry.picks.westFinal===results.westFinal)total+=4;if(results.champion&&entry.picks.champion===results.champion)total+=8;return{total};}

